// C solution (uses BFS, SPF sieve)
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>
#include <inttypes.h>
#define MOD 998244353ULL
#define MAXV 1000000

static int spf[MAXV + 1];

void build_spf() {
    for (int i = 2; i <= MAXV; ++i) if (!spf[i]) {
        for (int j = i; j <= MAXV; j += i) if (!spf[j]) spf[j] = i;
    }
}

// multiply all b for a given prime a, store as 64‑bit (will not overflow 10^12)
static uint64_t mult_factor[MAXV + 1];

uint64_t bfs(uint64_t start) {
    if (start == 1) return 0;
    // hash map: open addressing
    const size_t HSIZE = 1 << 21; // ~2 million slots
    uint64_t *key = (uint64_t*)calloc(HSIZE, sizeof(uint64_t));
    uint64_t *dist = (uint64_t*)calloc(HSIZE, sizeof(uint64_t));
    size_t mask = HSIZE - 1;
    // queue
    uint64_t *q = (uint64_t*)malloc(HSIZE * sizeof(uint64_t));
    size_t qh = 0, qt = 0;
    // insert start
    size_t h = start & mask;
    while (key[h]) h = (h + 1) & mask;
    key[h] = start; dist[h] = 0;
    q[qt++] = start;
    while (qh < qt) {
        uint64_t cur = q[qh++];
        // find its distance
        size_t hc = cur & mask;
        while (key[hc] != cur) hc = (hc + 1) & mask;
        uint64_t curd = dist[hc];
        // factorise cur
        uint64_t tmp = cur;
        while (tmp > 1) {
            int p = (tmp <= MAXV) ? spf[tmp] : tmp; // tmp always ≤ MAXV in our bound
            // skip same prime repetitions
            while (tmp % p == 0) tmp /= p;
            uint64_t nxt = cur / p * mult_factor[p];
            // insert if not visited
            size_t hn = nxt & mask;
            while (key[hn] && key[hn] != nxt) hn = (hn + 1) & mask;
            if (!key[hn]) {
                key[hn] = nxt;
                dist[hn] = (curd + 1) % MOD;
                if (nxt == 1) {
                    uint64_t ans = (curd + 1) % MOD;
                    free(key); free(dist); free(q);
                    return ans;
                }
                q[qt++] = nxt;
            }
        }
    }
    free(key); free(dist); free(q);
    return (uint64_t)(-1);
}

int main(){
    build_spf();
    uint64_t N; int M; if (scanf("%" SCNu64 " %d", &N, &M)!=2) return 0;
    for (int i=0;i<=MAXV;i++) mult_factor[i]=1ULL;
    for (int i=0;i<M;i++){
        int a,b; scanf("%d %d", &a, &b);
        mult_factor[a] *= (uint64_t)b;
    }
    uint64_t ans = bfs(N);
    if (ans == (uint64_t)(-1)) printf("-1\n");
    else printf("%" PRIu64 "\n", ans);
    return 0;
}

