// C++17 solution (BFS with unordered_map)
#include <bits/stdc++.h>
using namespace std;
const long long MOD = 998244353LL;
const int MAXV = 1'000'000;
vector<int> spf(MAXV+1);
void build_spf(){
    for(int i=2;i<=MAXV;i++) if(!spf[i])
        for(int j=i;j<=MAXV;j+=i) if(!spf[j]) spf[j]=i;
}
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    build_spf();
    long long N; int M; if(!(cin>>N>>M)) return 0;
    vector<unsigned long long> mult(MAXV+1,1ULL);
    for(int i=0;i<M;i++){
        int a,b;cin>>a>>b; mult[a]*=b;
    }
    if(N==1){cout<<0<<"\n";return 0;}
    unordered_map<unsigned long long,long long> dist;
    queue<unsigned long long> q;
    dist[N]=0; q.push(N);
    while(!q.empty()){
        unsigned long long cur=q.front();q.pop();
        long long d=dist[cur];
        unsigned long long tmp=cur;
        // factorise cur using spf (cur never exceeds 1e12, but we only need primes <=1e6)
        unordered_set<int> primes;
        while(tmp>1){
            int p = (tmp<=MAXV)? spf[tmp] : (int)tmp; // safe because tmp fits in 64‑bit and primes >1e6 appear only as whole number
            primes.insert(p);
            while(tmp%p==0) tmp/=p;
        }
        for(int p:primes){
            unsigned long long nxt = cur / p * mult[p];
            if(!dist.count(nxt)){
                long long nd = (d+1)%MOD;
                if(nxt==1){cout<<nd<<"\n";return 0;}
                dist[nxt]=nd; q.push(nxt);
            }
        }
    }
    cout<<-1<<"\n";
    return 0;
}
